let cachedProblems;

const MAX_LIMIT = 50;

/**
 * Normalize tags filter into a lowercase array.
 * @param {string|Array<string>} rawTags
 * @returns {Array<string>}
 */
function normalizeTags(rawTags) {
  if (!rawTags && rawTags !== '') {
    return [];
  }
  const list = Array.isArray(rawTags) ? rawTags : String(rawTags).split(',');
  return list
    .map((tag) => String(tag || '').trim().toLowerCase())
    .filter((tag) => tag);
}

/**
 * Check whether the problem contains at least one of the requested tags.
 * @param {Object} problem
 * @param {Array<string>} tags
 * @returns {boolean}
 */
function problemHasTags(problem, tags) {
  if (!tags || tags.length === 0) {
    return true;
  }
  if (!problem.tags || !Array.isArray(problem.tags)) {
    return false;
  }
  const problemTags = problem.tags.map((t) => String(t).toLowerCase());
  return tags.some((tag) => problemTags.includes(tag));
}

/**
 * Load problems from JSON file and cache them.
 * @returns {Array<Object>} problems
 */
function loadProblems() {
  if (cachedProblems) {
    return cachedProblems;
  }
  const filePath = path.join(__dirname, '../../data/problems.json');
  const raw = fs.readFileSync(filePath, 'utf8');
  cachedProblems = JSON.parse(raw);
  return cachedProblems;
}

/**
 * Deduplicate and sort array of strings case-insensitively.
 * @param {Array<string>} arr
 * @returns {Array<string>}
 */
function dedupeAndSortCaseInsensitive(arr) {
  const set = new Set();
  arr.forEach((item) => {
    if (typeof item === 'string') {
      set.add(item);
    }
  });
  return Array.from(set).sort((a, b) => a.toLowerCase().localeCompare(b.toLowerCase()));
}

